package com.google.gson.internal.bind;
import com.google.gson.JsonArray;
import com.google.gson.JsonNull;
import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.Reader;
import java.util.Arrays;
import java.util.Map;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;

class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;
  private JsonObject jsonObject;

  @BeforeEach
  void setUp() throws Exception {
    jsonObject = new JsonObject();
    jsonTreeReader = new JsonTreeReader(jsonObject);

    // Use reflection to set private fields stack and stackSize to simulate state before endObject
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(jsonTreeReader);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);

    Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
    pathNamesField.setAccessible(true);
    String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);

    // Setup initial stack state:
    // stack[0] = jsonObject (object)
    // stack[1] = iterator over entrySet (empty iterator)
    // stackSize = 2
    stack[0] = jsonObject;
    stack[1] = jsonObject.entrySet().iterator();
    stackSizeField.setInt(jsonTreeReader, 2);

    // Setup pathNames and pathIndices for stackSize=2
    pathNames[0] = "root";
    pathNames[1] = "child";
    pathIndices[0] = 0;
    pathIndices[1] = 0;
  }

  @Test
  void endObject_shouldPopStackAndIncrementPathIndices() throws Exception {
    // Spy on jsonTreeReader to mock expect method to avoid IOException
    JsonTreeReader spyReader = spy(jsonTreeReader);

    // Mock expect(JsonToken.END_OBJECT) to do nothing (avoid exception)
    doNothing().when(spyReader).expect(JsonToken.END_OBJECT);

    // Use reflection to invoke private popStack() method to verify it is called twice
    Method popStackMethod = JsonTreeReader.class.getDeclaredMethod("popStack");
    popStackMethod.setAccessible(true);

    // Spy to count popStack calls
    doCallRealMethod().when(spyReader).popStack();

    // Call endObject
    spyReader.endObject();

    // Verify pathNames[stackSize - 1] is null (stackSize before pop is 2, after pop is 0)
    Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
    pathNamesField.setAccessible(true);
    String[] pathNames = (String[]) pathNamesField.get(spyReader);

    // pathNames[1] should be null after endObject
    assertNull(pathNames[1]);

    // Verify stackSize after endObject is 0 (2 - 2 pops)
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    int stackSize = stackSizeField.getInt(spyReader);
    assertEquals(0, stackSize);

    // Verify pathIndices[stackSize - 1] incremented if stackSize > 0
    // Here stackSize == 0, so no increment expected
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(spyReader);
    // pathIndices[0] was 0, remains 0 because stackSize == 0 after pops
    assertEquals(0, pathIndices[0]);

    // Now test case where stackSize > 0 after pops
    // Setup again with stackSize=3 to test increment
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(spyReader);

    stack[0] = jsonObject;
    stack[1] = jsonObject.entrySet().iterator();
    stack[2] = jsonObject.entrySet().iterator();
    stackSizeField.setInt(spyReader, 3);

    String[] pathNames2 = (String[]) pathNamesField.get(spyReader);
    pathNames2[2] = "lastName";

    int[] pathIndices2 = (int[]) pathIndicesField.get(spyReader);
    pathIndices2[2] = 5;

    // Call endObject again
    spyReader.endObject();

    // After two pops, stackSize = 1, so pathIndices[0] incremented
    int newStackSize = stackSizeField.getInt(spyReader);
    assertEquals(1, newStackSize);

    // pathNames[2] cleared
    assertNull(pathNames2[2]);

    // pathIndices[0] incremented from 0 to 1
    assertEquals(1, pathIndices2[0]);
  }

  @Test
  void endObject_expectThrows_shouldThrowIOException() throws Exception {
    JsonTreeReader spyReader = spy(jsonTreeReader);

    // Setup expect to throw IOException
    doThrow(new IOException("expected token not found")).when(spyReader).expect(JsonToken.END_OBJECT);

    IOException exception = assertThrows(IOException.class, spyReader::endObject);
    assertEquals("expected token not found", exception.getMessage());
  }
}

